func carouselClass(cfg CarouselConfig) string {
	return joinClasses(
		"carousel",
		carouselSnapClass(cfg.Snap),
		carouselDirectionClass(cfg.Direction),
		cfg.Class,
	)
}

func carouselItemClass(slide CarouselSlide, cfg CarouselConfig) string {
	classes := []string{"carousel-item"}
	if slide.Full {
		classes = append(classes, "w-full")
	}
	if slide.Width != "" {
		classes = append(classes, slide.Width)
	}
	if slide.Class != "" {
		classes = append(classes, slide.Class)
	}
	return joinClasses(classes...)
}

func carouselSnapClass(s string) string {
	switch strings.TrimSpace(s) {
	case "center":
		return "carousel-center"
	case "end":
		return "carousel-end"
	default:
		// "start" is the default; daisyUI applies it implicitly so we
		// don't emit a class for it (matches the docs).
		return ""
	}
}

func carouselDirectionClass(s string) string {
	switch strings.TrimSpace(s) {
	case "vertical":
		return "carousel-vertical"
	default:
		return ""
	}
}

// carouselControlHref returns the anchor href for the next/prev control,
// wrapping around at the ends.
func carouselControlHref(i int, slides []CarouselSlide) string {
	if len(slides) == 0 {
		return "#"
	}
	n := len(slides)
	if i < 0 {
		i = n - 1
	}
	if i >= n {
		i = 0
	}
	slide := slides[i]
	if slide.ID == "" {
		return "#"
	}
	return "#" + slide.ID
}

// carouselIndicatorLabel returns the slide's id (or a fallback ordinal) as
// the indicator button label.
func carouselIndicatorLabel(slide CarouselSlide) string {
	if slide.ID != "" {
		return slide.ID
	}
	return "•"
}

